  1→/// <reference types="@cloudflare/workers-types" />
  2→
  3→import { RPCHandler } from "@orpc/server/fetch";
  4→import * as schema from "@rudel/sql-schema";
  5→import { drizzle } from "drizzle-orm/d1";
  6→import { createAuth } from "./auth.js";
  7→import { getClickhouse } from "./clickhouse.js";
  8→import { ingestSession } from "./ingest.js";
  9→import { authMiddleware, os } from "./middleware.js";
 10→
 11→interface Env {
 12→	DB: D1Database;
 13→	APP_URL: string;
 14→	BETTER_AUTH_SECRET: string;
 15→	ALLOWED_ORIGIN: string;
 16→	TRUSTED_ORIGINS?: string;
 17→	GOOGLE_CLIENT_ID?: string;
 18→	GOOGLE_CLIENT_SECRET?: string;
 19→	GITHUB_CLIENT_ID?: string;
 20→	GITHUB_CLIENT_SECRET?: string;
 21→	CLICKHOUSE_URL: string;
 22→	CLICKHOUSE_USERNAME?: string;
 23→	CLICKHOUSE_PASSWORD?: string;
 24→}
 25→
 26→function buildRouter() {
 27→	const health = os.health.handler(() => ({
 28→		status: "ok" as const,
 29→		timestamp: Date.now(),
 30→	}));
 31→
 32→	const me = os.me.use(authMiddleware).handler(({ context }) => ({
 33→		id: context.user.id,
 34→		email: context.user.email,
 35→		name: context.user.name,
 36→	}));
 37→
 38→	const ingestSessionHandler = os.ingestSession
 39→		.use(authMiddleware)
 40→		.handler(async ({ input, context }) => {
 41→			await ingestSession(getClickhouse(), input, {
 42→				userId: context.user.id,
 43→				organizationId: context.user.id,
 44→			});
 45→			return { success: true as const, sessionId: input.sessionId };
 46→		});
 47→
 48→	return os.router({ health, me, ingestSession: ingestSessionHandler });
 49→}
 50→
 51→function corsHeaders(
 52→	origin: string | null,
 53→	allowedOrigin: string,
 54→): Record<string, string> {
 55→	if (origin !== allowedOrigin) return {};
 56→	return {
 57→		"Access-Control-Allow-Origin": allowedOrigin,
 58→		"Access-Control-Allow-Credentials": "true",
 59→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 60→		"Access-Control-Allow-Headers": "Content-Type, Authorization",
 61→	};
 62→}
 63→
 64→export default {
 65→	async fetch(request: Request, env: Env): Promise<Response> {
 66→		// Bridge env bindings to process.env for libraries that read it
 67→		process.env.CLICKHOUSE_URL = env.CLICKHOUSE_URL;
 68→		process.env.CLICKHOUSE_USERNAME = env.CLICKHOUSE_USERNAME;
 69→		process.env.CLICKHOUSE_PASSWORD = env.CLICKHOUSE_PASSWORD;
 70→
 71→		const db = drizzle(env.DB, { schema });
 72→
 73→		const socialProviders: Record<
 74→			string,
 75→			{ clientId: string; clientSecret: string }
 76→		> = {};
 77→		if (env.GOOGLE_CLIENT_ID && env.GOOGLE_CLIENT_SECRET) {
 78→			socialProviders.google = {
 79→				clientId: env.GOOGLE_CLIENT_ID,
 80→				clientSecret: env.GOOGLE_CLIENT_SECRET,
 81→			};
 82→		}
 83→		if (env.GITHUB_CLIENT_ID && env.GITHUB_CLIENT_SECRET) {
 84→			socialProviders.github = {
 85→				clientId: env.GITHUB_CLIENT_ID,
 86→				clientSecret: env.GITHUB_CLIENT_SECRET,
 87→			};
 88→		}
 89→
 90→		const trustedOrigins = env.TRUSTED_ORIGINS
 91→			? env.TRUSTED_ORIGINS.split(",").map((o) => o.trim())
 92→			: [];
 93→
 94→		const auth = createAuth(db, {
 95→			appURL: env.APP_URL,
 96→			secret: env.BETTER_AUTH_SECRET,
 97→			socialProviders,
 98→			trustedOrigins,
 99→		});
100→
101→		const router = buildRouter();
102→		const rpcHandler = new RPCHandler(router);
103→
104→		const origin = request.headers.get("Origin");
105→		const allowedOrigin = env.ALLOWED_ORIGIN ?? env.APP_URL;
106→		const cors = corsHeaders(origin, allowedOrigin);
107→
108→		if (request.method === "OPTIONS") {
109→			return new Response(null, { status: 204, headers: cors });
110→		}
111→
112→		const url = new URL(request.url);
113→
114→		if (url.pathname === "/api/cli-token") {
115→			const session = await auth.api.getSession({
116→				headers: request.headers,
117→			});
118→			if (!session) {
119→				return new Response(JSON.stringify({ error: "Not authenticated" }), {
120→					status: 401,
121→					headers: { ...cors, "Content-Type": "application/json" },
122→				});
123→			}
124→			return new Response(JSON.stringify({ token: session.session.token }), {
125→				status: 200,
126→				headers: { ...cors, "Content-Type": "application/json" },
127→			});
128→		}
129→
130→		if (url.pathname.startsWith("/api/auth")) {
131→			const response = await auth.handler(request);
132→			for (const [key, value] of Object.entries(cors)) {
133→				response.headers.set(key, value);
134→			}
135→			return response;
136→		}
137→
138→		const context = await (async () => {
139→			const session = await auth.api.getSession({
140→				headers: request.headers,
141→			});
142→			return {
143→				user: session?.user ?? null,
144→				session: session?.session ?? null,
145→			};
146→		})();
147→
148→		const { matched, response } = await rpcHandler.handle(request, {
149→			prefix: "/rpc",
150→			context,
151→		});
152→
153→		if (matched) {
154→			for (const [key, value] of Object.entries(cors)) {
155→				response.headers.set(key, value);
156→			}
157→			return response;
158→		}
159→
160→		return new Response("Not found", { status: 404, headers: cors });
161→	},
162→};
