/**
 * Session Upload Hook
 *
 * Hook entry point that receives session metadata via stdin
 * and uploads the transcript to the backend.
 *
 * Logs are written to: ~/.claude/logs/session-upload.log
 */

import { getLogger } from "@logtape/logtape";
import { dirname } from "path";
import {
  uploadSession,
  readTranscript,
  extractAgentIds,
  readSubagentFiles,
  getRepositoryName,
  getGitBranch,
  getGitSha,
  classifySession,
  type IngestRequest,
} from "./lib/session-upload-core";

// Types
interface StdinInput {
  session_id: string;
  transcript_path: string;
  cwd: string;
  permission_mode: string;
  hook_event_name: string;
  stop_hook_active: boolean;
}

// Main Function
const logger = getLogger(["compound", "session-upload"]);

async function main(): Promise<void> {
  logger.debug("Session upload hook started");

  try {
    const stdinContent = await readStdin();
    const input = parseStdinInput(stdinContent);

    if (!input) {
      return;
    }

    const { session_id, transcript_path, cwd } = input;

    if (!session_id || !transcript_path) {
      logger.error("Missing session_id or transcript_path");
      return;
    }

    const content = await readTranscript(transcript_path);
    if (!content) {
      return;
    }

    // Extract and read subagent files
    const agentIds = extractAgentIds(content);
    const sessionDir = dirname(transcript_path);
    const subagents =
      agentIds.length > 0
        ? await readSubagentFiles(sessionDir, agentIds, session_id)
        : undefined;

    if (subagents?.length) {
      logger.info("Found {count} subagent(s) for session {sessionId}", {
        count: subagents.length,
        sessionId: session_id,
      });
    }

    // Get git metadata and classify session in parallel
    const [repository, gitBranch, gitSha, tag] = await Promise.all([
      getRepositoryName(cwd),
      getGitBranch(cwd),
      getGitSha(cwd),
      classifySession(content),
    ]);

    if (repository) {
      logger.debug("Repository name: {repository}", { repository });
    }

    if (tag) {
      logger.info("Session classified as: {tag}", { tag });
    }

    const request: IngestRequest = {
      sessionId: session_id,
      projectPath: cwd,
      repository: repository ?? undefined,
      gitBranch: gitBranch ?? undefined,
      gitSha: gitSha ?? undefined,
      tag: tag ?? undefined,
      content,
      subagents: subagents?.length ? subagents : undefined,
    };

    // Log request metadata before upload (excluding content for brevity)
    logger.info(
      "Preparing upload: sessionId={sessionId}, repo={repository}, branch={gitBranch}, tag={tag}, contentBytes={contentBytes}, subagents={subagentCount}",
      {
        sessionId: request.sessionId,
        repository: request.repository ?? "none",
        gitBranch: request.gitBranch ?? "none",
        tag: request.tag ?? "none",
        contentBytes: request.content.length,
        subagentCount: request.subagents?.length ?? 0,
      },
    );

    await uploadSession(request);
  } catch (error) {
    logger.error("Unexpected error: {error}", { error });
  }
}

// Utility Functions

/**
 * Read stdin using platform-specific approach
 * - Unix: Bun.stdin.stream() (proper Bun API)
 * - Windows: process.stdin directly
 * @see https://bun.sh/docs/api/stdin
 */
async function readStdin(): Promise<string> {
  if (process.stdin.isTTY) {
    return "";
  }

  const isWindows = process.platform === "win32";

  if (isWindows) {
    // On Windows, read from process.stdin directly
    const chunks: Buffer[] = [];
    for await (const chunk of process.stdin) {
      chunks.push(Buffer.from(chunk));
    }
    return Buffer.concat(chunks).toString("utf8");
  }

  // Unix: use Bun.stdin.stream() - the proper cross-platform Bun API
  const chunks: Uint8Array[] = [];

  try {
    for await (const chunk of Bun.stdin.stream()) {
      chunks.push(chunk);
    }
  } catch (error: any) {
    // Handle cases where stdin is not available
    if (error.code === "EBADF" || error.code === "ENXIO") {
      logger.debug("No stdin available");
      return "";
    }
    throw error;
  }

  return Buffer.concat(chunks).toString("utf8");
}

/**
 * Parse stdin input to get session metadata
 */
function parseStdinInput(input: string): StdinInput | null {
  if (!input.trim()) {
    logger.debug("Empty stdin input");
    return null;
  }

  try {
    const parsed = JSON.parse(input) as StdinInput;
    logger.debug("Parsed stdin: session_id={sessionId}, cwd={cwd}", {
      sessionId: parsed.session_id,
      cwd: parsed.cwd,
    });
    return parsed;
  } catch (error) {
    logger.error("Failed to parse stdin input: {error}", { error });
    return null;
  }
}

main();

{
  "name": "compound",
  "description": "Continuous learning plugin that compounds knowledge, skills, and learnings across sessions.",
  "version": "0.1.9",
  "author": {
    "name": "Marc Höffl",
    "email": "marc.hoeffl@gmail.com"
  },
  "keywords": [
    "learning",
    "continuous-improvement",
    "knowledge-management",
    "feedback",
    "retrospective"
  ],
  "license": "MIT",
  "repository": "https://github.com/numiadata/claude-marketplace",
  "homepage": "https://github.com/numiadata/claude-marketplace",
  "hooks": {
