143→/**
144→ * Decode an encoded project directory name back to the actual filesystem path.
145→ * Handles directory names that contain dashes by checking if paths exist.
146→ *
147→ * Example: "-Users-marc-Workspace-claude-marketplace" -> "/Users/marc/Workspace/claude-marketplace"
148→ */
149→async function decodeProjectPath(encodedDir: string): Promise<string> {
150→  // Remove leading dash and split by dash
151→  const parts = encodedDir.replace(/^-/, "").split("-");
152→
153→  // Recursive function to find the valid path
154→  async function findPath(
155→    partIndex: number,
156→    currentPath: string
157→  ): Promise<string | null> {
158→    if (partIndex >= parts.length) {
159→      // Check if this is the final valid path
160→      try {
161→        const stat = await Bun.file(currentPath).stat();
162→        if (stat !== null) {
163→          return currentPath;
164→        }
165→      } catch {
166→        // Path doesn't exist
167→      }
168→      return null;
169→    }
170→
171→    // Try consuming multiple parts with dashes (greedy - try longest first)
172→    for (let endIndex = parts.length; endIndex > partIndex; endIndex--) {
173→      const segment = parts.slice(partIndex, endIndex).join("-");
174→      const testPath = currentPath
175→        ? `${currentPath}/${segment}`
176→        : `/${segment}`;
177→
178→      // Check if this path exists
179→      try {
180→        const stat = await Bun.file(testPath).stat();
181→        if (stat !== null) {
182→          // If we've consumed all parts and path exists, return it
183→          if (endIndex === parts.length) {
184→            return testPath;
185→          }
186→          // Otherwise, continue recursively
187→          const result = await findPath(endIndex, testPath);
188→          if (result) {
189→            return result;
190→          }
191→        }
192→      } catch {
193→        // Path doesn't exist, try shorter segment
194→      }
195→    }
196→
197→    return null;
198→  }
199→
200→  const result = await findPath(0, "");
201→  if (result) {
202→    return result;
203→  }
204→
205→  // Fallback: simple dash-to-slash replacement
206→  return "/" + parts.join("/");
207→}
