209→/**
210→ * Find a session by ID and return its transcript path and project path
211→ */
212→export async function findSessionById(
213→  sessionId: string
214→): Promise<SessionInfo | null> {
215→  try {
216→    const projectDirs = await readdir(SESSIONS_BASE_DIR);
217→    const sessionFileName = `${sessionId}.jsonl`;
218→
219→    for (const projectDir of projectDirs) {
220→      const sessionDir = join(SESSIONS_BASE_DIR, projectDir);
221→      try {
222→        const files = await readdir(sessionDir);
223→        if (files.includes(sessionFileName)) {
224→          const transcriptPath = join(sessionDir, sessionFileName);
225→
226→          // Decode the encoded project directory to the actual filesystem path
227→          const actualProjectPath = await decodeProjectPath(projectDir);
228→
229→          logger.debug("Found session {sessionId} at {path}", {
230→            sessionId,
231→            path: transcriptPath,
232→          });
233→          return { transcriptPath, projectPath: actualProjectPath, sessionDir };
234→        }
235→      } catch {
236→        // Can't read this project directory
237→        continue;
238→      }
239→    }
240→
241→    logger.error("Session {sessionId} not found", { sessionId });
242→    return null;
243→  } catch (error) {
244→    logger.error("Error searching for session: {error}", { error });
245→    return null;
246→  }
