251→/**
252→ * Read transcript file content with retry for timing issues
253→ */
254→export async function readTranscript(
255→  transcriptPath: string
256→): Promise<string | null> {
257→  const maxRetries = 5;
258→  const delayMs = 500;
259→
260→  for (let attempt = 1; attempt <= maxRetries; attempt++) {
261→    try {
262→      const file = Bun.file(transcriptPath);
263→      const exists = await file.exists();
264→      if (!exists) {
265→        if (attempt < maxRetries) {
266→          logger.debug(
267→            "Transcript file not found (attempt {attempt}/{max}), retrying in {delay}ms: {path}",
268→            { attempt, max: maxRetries, delay: delayMs, path: transcriptPath }
269→          );
270→          await new Promise((resolve) => setTimeout(resolve, delayMs));
271→          continue;
272→        }
273→        logger.error("Transcript file not found after {max} attempts: {path}", {
274→          max: maxRetries,
275→          path: transcriptPath,
276→        });
277→        return null;
278→      }
279→      const content = await file.text();
280→      logger.debug("Read transcript: {bytes} bytes", { bytes: content.length });
281→      return content;
282→    } catch (error) {
283→      if (attempt < maxRetries) {
284→        logger.debug("Failed to read transcript (attempt {attempt}), retrying: {error}", {
285→          attempt,
286→          error,
287→        });
288→        await new Promise((resolve) => setTimeout(resolve, delayMs));
289→        continue;
290→      }
291→      logger.error("Failed to read transcript: {error}", { error });
292→      return null;
293→    }
294→  }
295→  return null;
296→}
