298→/**
299→ * Extract agent IDs referenced in a session transcript.
300→ * Agents are spawned via the Task tool and their IDs are recorded in toolUseResult.agentId
301→ */
302→export function extractAgentIds(sessionContent: string): string[] {
303→  const agentIds = new Set<string>();
304→
305→  for (const line of sessionContent.split("\n")) {
306→    if (!line.trim()) continue;
307→
308→    try {
309→      const entry = JSON.parse(line);
310→      // Agent IDs appear in toolUseResult.agentId when Task tool completes
311→      if (entry.toolUseResult?.agentId) {
312→        agentIds.add(entry.toolUseResult.agentId);
313→      }
314→    } catch {
315→      // Skip malformed lines
316→    }
317→  }
318→
319→  const ids = Array.from(agentIds);
320→  logger.debug("Found {count} subagent(s) in session: {ids}", {
321→    count: ids.length,
322→    ids: ids.join(", "),
323→  });
324→  return ids;
325→}
