327→/**
328→ * Read all subagent files for a session.
329→ * Subagent transcripts can be stored in multiple locations:
330→ * 1. {sessionDir}/agent-{agentId}.jsonl (legacy)
331→ * 2. {sessionDir}/{sessionId}/subagents/agent-{agentId}.jsonl (new format)
332→ */
333→export async function readSubagentFiles(
334→  sessionDir: string,
335→  agentIds: string[],
336→  sessionId?: string
337→): Promise<SubagentFile[]> {
338→  const subagents: SubagentFile[] = [];
339→
340→  for (const agentId of agentIds) {
341→    // Try multiple locations for the subagent file
342→    const possiblePaths = [
343→      join(sessionDir, `agent-${agentId}.jsonl`),
344→      ...(sessionId
345→        ? [join(sessionDir, sessionId, "subagents", `agent-${agentId}.jsonl`)]
346→        : []),
347→    ];
348→
349→    let found = false;
350→    for (const agentPath of possiblePaths) {
351→      try {
352→        const file = Bun.file(agentPath);
353→        if (await file.exists()) {
354→          const content = await file.text();
355→          subagents.push({ agentId, content });
356→          logger.debug("Read subagent {agentId}: {bytes} bytes from {path}", {
357→            agentId,
358→            bytes: content.length,
359→            path: agentPath,
360→          });
361→          found = true;
362→          break;
363→        }
364→      } catch {
365→        // Try next path
366→      }
367→    }
368→
369→    if (!found) {
370→      logger.warn("Subagent file not found for {agentId}", { agentId });
371→    }
372→  }
373→
374→  return subagents;
