377→/**
378→ * Get the repository name for a given directory.
379→ * Looks for the git root, then reads package.json name or extracts from git remote.
380→ */
381→export async function getRepositoryName(cwd: string): Promise<string | null> {
382→  try {
383→    // Find git root directory
384→    const gitRootResult =
385→      await $`git -C ${cwd} rev-parse --show-toplevel`.quiet();
386→    if (gitRootResult.exitCode !== 0) {
387→      logger.debug("Not a git repository: {cwd}", { cwd });
388→      return null;
389→    }
390→    const gitRoot = gitRootResult.text().trim();
391→    logger.info("Git root: {gitRoot}", { gitRoot });
392→
393→    // Try package.json name first
394→    const packageJsonPath = join(gitRoot, "package.json");
395→    const packageFile = Bun.file(packageJsonPath);
396→    if (await packageFile.exists()) {
397→      try {
398→        const packageJson = await packageFile.json();
399→        if (packageJson.name) {
400→          logger.debug("Found repository name from package.json: {name}", {
401→            name: packageJson.name,
402→          });
403→          return packageJson.name;
404→        }
405→      } catch {
406→        // Invalid JSON, continue to git remote
407→      }
408→    }
409→
410→    // Fall back to git remote origin URL
411→    const remoteResult =
412→      await $`git -C ${gitRoot} remote get-url origin`.quiet();
413→    if (remoteResult.exitCode === 0) {
414→      const remoteUrl = remoteResult.text().trim();
415→      // Extract repo name from various URL formats:
416→      // - git@github.com:org/repo.git -> repo
417→      // - https://github.com/org/repo.git -> repo
418→      // - https://github.com/org/repo -> repo
419→      const match = remoteUrl.match(/[/:]([^/]+?)(?:\.git)?$/);
420→      if (match?.[1]) {
421→        logger.debug("Found repository name from git remote: {name}", {
422→          name: match[1],
423→        });
424→        return match[1];
425→      }
426→    }
427→
428→    // Fall back to directory name
429→    const dirName = gitRoot.split("/").pop();
430→    if (dirName) {
431→      logger.debug("Using directory name as repository: {name}", {
432→        name: dirName,
433→      });
434→      return dirName;
435→    }
436→
437→    return null;
438→  } catch (error) {
439→    logger.error("Failed to get repository name: {error}", { error });
440→    return null;
441→  }
442→}
