490→/**
491→ * Classify a session transcript using Claude CLI.
492→ * Returns one of the predefined tags based on the session content.
493→ */
494→export async function classifySession(
495→  content: string
496→): Promise<SessionTag | null> {
497→  const systemPrompt = `You are a session classifier. Analyze the Claude Code session transcript and classify it into exactly ONE of these categories:
498→
499→- research: Exploring codebase, understanding code, answering questions about how things work
500→- new_feature: Implementing new functionality or features
501→- bug_fix: Fixing bugs, errors, or unexpected behavior
502→- refactoring: Restructuring existing code without changing functionality
503→- documentation: Writing or updating documentation, comments, READMEs
504→- tests: Writing, updating, or fixing tests
505→
506→CRITICAL: Respond with ONLY the tag name. Nothing else. No explanation, no punctuation, no formatting. Just ONE of: research, new_feature, bug_fix, refactoring, documentation, tests`;
507→
508→  // Truncate content to avoid excessive API costs
509→  const truncatedContent = content.slice(0, 50000);
510→
511→  try {
512→    logger.debug("Classifying session with Claude CLI");
513→
514→    // Write content to temp file to avoid command-line length limits
515→    const tempDir = join(homedir(), ".claude", "temp");
516→    const tempFile = join(tempDir, `classify-${Date.now()}.txt`);
517→    await Bun.write(tempFile, `Classify this session transcript:\n\n${truncatedContent}`);
518→
519→    try {
520→      // IMPORTANT: --no-session-persistence prevents this from triggering SessionEnd hooks recursively
521→      // Pass the prompt via stdin as Claude CLI expects for --print mode
522→      const prompt = `Read and classify the session transcript in this file: ${tempFile}`;
523→      const isWindows = process.platform === "win32";
524→
525→      // On Windows, need to use shell mode
526→      const args = isWindows
527→        ? ["cmd", "/c", `echo ${prompt} | claude --output-format text --print --model haiku --no-session-persistence --dangerously-skip-permissions --system-prompt "${systemPrompt.replace(/"/g, '\\"')}"`]
528→        : ["sh", "-c", `echo '${prompt.replace(/'/g, "'\\''")}' | claude --output-format text --print --model haiku --no-session-persistence --dangerously-skip-permissions --system-prompt '${systemPrompt.replace(/'/g, "'\\''")}'`];
529→
530→      const proc = Bun.spawn(args, {
531→        stdout: "pipe",
532→        stderr: "pipe",
533→      });
534→
535→      const exitCode = await proc.exited;
536→      const stdout = await new Response(proc.stdout).text();
537→      const stderr = await new Response(proc.stderr).text();
538→
539→      if (exitCode !== 0) {
540→        logger.error("Claude CLI failed with exit code {code}, defaulting to 'other': {stderr}", {
541→          code: exitCode,
542→          stderr,
543→        });
544→        return "other";
545→      }
546→
547→      const output = stdout.trim().toLowerCase();
548→
549→      // First try exact match
550→      if (VALID_TAGS.includes(output as SessionTag)) {
551→        logger.info("Session classified as: {tag}", { tag: output });
552→        return output as SessionTag;
553→      }
554→
555→      // If model didn't follow instructions, search for valid tags in output
556→      // Use word boundaries to avoid partial matches (e.g., "tests" in "testing")
557→      for (const tag of VALID_TAGS) {
558→        // Match tag with word boundaries or common delimiters
559→        const patterns = [
560→          new RegExp(`\\b${tag}\\b`),           // word boundary
561→          new RegExp(`[:\`"']${tag}[:\`"']`),   // surrounded by delimiters
562→          new RegExp(`\\*\\*${tag}\\*\\*`),     // bold markdown
563→        ];
564→        if (patterns.some(p => p.test(output))) {
565→          logger.info("Session classified as: {tag} (extracted from verbose output)", { tag });
566→          return tag;
567→        }
568→      }
569→
570→      logger.warn("Could not extract valid tag from output, defaulting to 'other': {output}", { output: output.slice(0, 200) });
571→      return "other";
572→    } finally {
573→      // Clean up temp file
574→      try {
