 51→/**
 52→ * Find a real session ID from ~/.claude/projects/ for integration tests.
 53→ */
 54→async function findRealSessionId(): Promise<string> {
 55→	const sessionsBase = join(homedir(), ".claude", "projects");
 56→	const projectDirs = await readdir(sessionsBase);
 57→
 58→	for (const dir of projectDirs) {
 59→		const fullDir = join(sessionsBase, dir);
 60→		const files = await readdir(fullDir).catch(() => [] as string[]);
 61→		const sessionFile = files.find(
 62→			(f) =>
 63→				f.endsWith(".jsonl") &&
 64→				!f.startsWith("agent-") &&
 65→				f !== "sessions-index.json",
 66→		);
 67→		if (sessionFile) {
 68→			return sessionFile.replace(/\.jsonl$/, "");
 69→		}
 70→	}
 71→
 72→	throw new Error("No real session found in ~/.claude/projects/");
 73→}
