  1→/**
  2→ * Session Upload Hook
  3→ *
  4→ * Hook entry point that receives session metadata via stdin
  5→ * and uploads the transcript to the backend.
  6→ *
  7→ * Logs are written to: ~/.claude/logs/session-upload.log
  8→ */
  9→
 10→import { getLogger } from "@logtape/logtape";
 11→import { dirname } from "path";
 12→import {
 13→  uploadSession,
 14→  readTranscript,
 15→  extractAgentIds,
 16→  readSubagentFiles,
 17→  getRepositoryName,
 18→  getGitBranch,
 19→  getGitSha,
 20→  classifySession,
 21→  type IngestRequest,
 22→} from "./lib/session-upload-core";
 23→
 24→// Types
 25→interface StdinInput {
 26→  session_id: string;
 27→  transcript_path: string;
 28→  cwd: string;
 29→  permission_mode: string;
 30→  hook_event_name: string;
 31→  stop_hook_active: boolean;
 32→}
 33→
 34→// Main Function
 35→const logger = getLogger(["compound", "session-upload"]);
 36→
 37→async function main(): Promise<void> {
 38→  logger.debug("Session upload hook started");
 39→
 40→  try {
 41→    const stdinContent = await readStdin();
 42→    const input = parseStdinInput(stdinContent);
 43→
 44→    if (!input) {
 45→      return;
 46→    }
 47→
 48→    const { session_id, transcript_path, cwd } = input;
 49→
 50→    if (!session_id || !transcript_path) {
 51→      logger.error("Missing session_id or transcript_path");
 52→      return;
 53→    }
 54→
 55→    const content = await readTranscript(transcript_path);
 56→    if (!content) {
 57→      return;
 58→    }
 59→
 60→    // Extract and read subagent files
 61→    const agentIds = extractAgentIds(content);
 62→    const sessionDir = dirname(transcript_path);
 63→    const subagents =
 64→      agentIds.length > 0
 65→        ? await readSubagentFiles(sessionDir, agentIds, session_id)
 66→        : undefined;
 67→
 68→    if (subagents?.length) {
 69→      logger.info("Found {count} subagent(s) for session {sessionId}", {
 70→        count: subagents.length,
 71→        sessionId: session_id,
 72→      });
 73→    }
 74→
 75→    // Get git metadata and classify session in parallel
 76→    const [repository, gitBranch, gitSha, tag] = await Promise.all([
 77→      getRepositoryName(cwd),
 78→      getGitBranch(cwd),
 79→      getGitSha(cwd),
 80→      classifySession(content),
 81→    ]);
 82→
 83→    if (repository) {
 84→      logger.debug("Repository name: {repository}", { repository });
 85→    }
 86→
 87→    if (tag) {
 88→      logger.info("Session classified as: {tag}", { tag });
 89→    }
 90→
 91→    const request: IngestRequest = {
 92→      sessionId: session_id,
 93→      projectPath: cwd,
 94→      repository: repository ?? undefined,
 95→      gitBranch: gitBranch ?? undefined,
 96→      gitSha: gitSha ?? undefined,
 97→      tag: tag ?? undefined,
 98→      content,
 99→      subagents: subagents?.length ? subagents : undefined,
100→    };
101→
102→    // Log request metadata before upload (excluding content for brevity)
103→    logger.info(
104→      "Preparing upload: sessionId={sessionId}, repo={repository}, branch={gitBranch}, tag={tag}, contentBytes={contentBytes}, subagents={subagentCount}",
105→      {
106→        sessionId: request.sessionId,
107→        repository: request.repository ?? "none",
108→        gitBranch: request.gitBranch ?? "none",
109→        tag: request.tag ?? "none",
110→        contentBytes: request.content.length,
111→        subagentCount: request.subagents?.length ?? 0,
112→      },
113→    );
114→
115→    await uploadSession(request);
116→  } catch (error) {
117→    logger.error("Unexpected error: {error}", { error });
118→  }
119→}
120→
121→// Utility Functions
122→
123→/**
124→ * Read stdin using platform-specific approach
125→ * - Unix: Bun.stdin.stream() (proper Bun API)
126→ * - Windows: process.stdin directly
127→ * @see https://bun.sh/docs/api/stdin
128→ */
129→async function readStdin(): Promise<string> {
130→  if (process.stdin.isTTY) {
131→    return "";
132→  }
133→
134→  const isWindows = process.platform === "win32";
135→
136→  if (isWindows) {
137→    // On Windows, read from process.stdin directly
138→    const chunks: Buffer[] = [];
139→    for await (const chunk of process.stdin) {
140→      chunks.push(Buffer.from(chunk));
141→    }
142→    return Buffer.concat(chunks).toString("utf8");
143→  }
144→
145→  // Unix: use Bun.stdin.stream() - the proper cross-platform Bun API
146→  const chunks: Uint8Array[] = [];
147→
148→  try {
149→    for await (const chunk of Bun.stdin.stream()) {
150→      chunks.push(chunk);
151→    }
152→  } catch (error: any) {
153→    // Handle cases where stdin is not available
154→    if (error.code === "EBADF" || error.code === "ENXIO") {
155→      logger.debug("No stdin available");
156→      return "";
157→    }
158→    throw error;
159→  }
160→
161→  return Buffer.concat(chunks).toString("utf8");
162→}
163→
164→/**
165→ * Parse stdin input to get session metadata
166→ */
167→function parseStdinInput(input: string): StdinInput | null {
168→  if (!input.trim()) {
169→    logger.debug("Empty stdin input");
170→    return null;
171→  }
172→
173→  try {
174→    const parsed = JSON.parse(input) as StdinInput;
175→    logger.debug("Parsed stdin: session_id={sessionId}, cwd={cwd}", {
176→      sessionId: parsed.session_id,
177→      cwd: parsed.cwd,
178→    });
179→    return parsed;
180→  } catch (error) {
181→    logger.error("Failed to parse stdin input: {error}", { error });
182→    return null;
183→  }
184→}
185→
