 1→import { buildCommand } from "@stricli/core";
 2→import { loadCredentials } from "../lib/credentials.js";
 3→
 4→async function runWhoami(): Promise<void> {
 5→	const write = (msg: string) => process.stdout.write(`${msg}\n`);
 6→	const writeError = (msg: string) => process.stderr.write(`${msg}\n`);
 7→
 8→	const credentials = loadCredentials();
 9→	if (!credentials) {
10→		write("Not logged in. Run `rudel login` to authenticate.");
11→		return;
12→	}
13→
14→	const response = await fetch(`${credentials.apiBaseUrl}/rpc/me`, {
15→		method: "POST",
16→		headers: {
17→			"Content-Type": "application/json",
18→			Authorization: `Bearer ${credentials.token}`,
19→		},
20→		body: JSON.stringify({}),
21→	});
22→
23→	if (!response.ok) {
24→		writeError(
25→			"Session expired or invalid. Run `rudel login` to re-authenticate.",
26→		);
27→		process.exitCode = 1;
28→		return;
29→	}
30→
31→	const body = (await response.json()) as {
32→		json: { id: string; email: string; name: string };
33→	};
34→	write(`Logged in as ${body.json.name} (${body.json.email})`);
35→}
36→
