 1→import { createORPCClient } from "@orpc/client";
 2→import { RPCLink } from "@orpc/client/fetch";
 3→import type { ContractRouterClient } from "@orpc/contract";
 4→import type { contract } from "@rudel/api-routes";
 5→import type { IngestRequest, UploadResult } from "./types.js";
 6→
 7→export interface UploadConfig {
 8→	endpoint: string;
 9→	token: string;
10→}
11→
12→/**
13→ * Upload a session transcript to the backend via oRPC.
14→ */
15→export async function uploadSession(
16→	request: IngestRequest,
17→	config: UploadConfig,
18→): Promise<UploadResult> {
19→	const link = new RPCLink({
20→		url: config.endpoint,
21→		headers: {
22→			Authorization: `Bearer ${config.token}`,
23→		},
24→	});
25→
26→	const client: ContractRouterClient<typeof contract> = createORPCClient(link);
27→
28→	try {
29→		await client.ingestSession(request);
30→		return { success: true, status: 200 };
31→	} catch (error) {
32→		return { success: false, error: String(error) };
33→	}
34→}
