107→	test("whoami: shows user info with valid credentials", async () => {
108→		// Ensure credentials are stored
109→		saveCredentialsToDir(configDir, sessionToken, worker.baseUrl);
110→
111→		const cliPath = join(import.meta.dir, "..", "bin", "cli.ts");
112→		const proc = Bun.spawn(["bun", cliPath, "whoami"], {
113→			env: {
114→				...process.env,
115→				RUDEL_CONFIG_DIR: configDir,
116→			},
117→			stdout: "pipe",
118→			stderr: "pipe",
119→		});
120→
121→		const exitCode = await proc.exited;
122→		const stdout = await new Response(proc.stdout).text();
123→		const stderr = await new Response(proc.stderr).text();
124→
