  1→import { afterAll, beforeAll, describe, expect, test } from "bun:test";
  2→import { mkdir, mkdtemp, rm, writeFile } from "node:fs/promises";
  3→import { tmpdir } from "node:os";
  4→import { join } from "node:path";
  5→import type { IngestRequest } from "../lib/types.js";
  6→import { uploadSession } from "../lib/uploader.js";
  7→import {
  8→	signUpTestUser,
  9→	startTestWorker,
 10→	type TestWorker,
 11→} from "./helpers/wrangler-server.js";
 12→
 13→let worker: TestWorker;
 14→let bearerToken: string;
 15→let tempDir: string;
 16→
 17→beforeAll(async () => {
 18→	tempDir = await mkdtemp(join(tmpdir(), "rudel-api-test-"));
 19→	worker = await startTestWorker();
 20→	bearerToken = await signUpTestUser(worker.baseUrl);
 21→}, 60_000);
 22→
 23→afterAll(async () => {
 24→	await worker?.stop();
 25→	if (tempDir) {
 26→		await rm(tempDir, { recursive: true, force: true }).catch(() => {});
 27→	}
 28→});
 29→
 30→describe("CLI upload to local API", () => {
 31→	test("uploads a session via uploadSession to the local API", async () => {
 32→		expect(bearerToken).toBeTruthy();
 33→
 34→		const testId = `cli_api_test_${Date.now()}`;
 35→		const request: IngestRequest = {
 36→			sessionId: testId,
 37→			projectPath: "/test/cli-api-upload",
 38→			repository: "test-repo",
 39→			gitBranch: "main",
 40→			gitSha: "abc123",
 41→			tag: "tests",
 42→			content: "cli api integration test content",
 43→			subagents: [{ agentId: "sub-1", content: "subagent content" }],
 44→		};
 45→
 46→		// Retry up to 3 times — wrangler dev + ClickHouse can be slow to accept
 47→		// the first request after startup (race condition with D1/CH readiness).
 48→		let result = { success: false, error: "not attempted" } as Awaited<
 49→			ReturnType<typeof uploadSession>
 50→		>;
 51→		for (let attempt = 0; attempt < 3; attempt++) {
 52→			result = await uploadSession(request, {
 53→				endpoint: worker.rpcUrl,
 54→				token: bearerToken,
 55→			});
 56→			if (result.success) break;
 57→			await Bun.sleep(1000);
 58→		}
 59→
 60→		if (!result.success) {
 61→			throw new Error(`uploadSession failed after 3 attempts: ${result.error}`);
 62→		}
 63→		expect(result.status).toBe(200);
 64→	}, 30_000);
 65→
 66→	test("full CLI upload via subprocess to local API", async () => {
 67→		expect(bearerToken).toBeTruthy();
 68→
 69→		const projectDir = join(tempDir, "cli-e2e-test");
 70→		await mkdir(projectDir, { recursive: true });
 71→
 72→		// Write credentials file so the CLI subprocess can authenticate
 73→		const credDir = join(tempDir, "cli-creds");
 74→		await mkdir(credDir, { recursive: true });
 75→		await writeFile(
 76→			join(credDir, "credentials.json"),
 77→			JSON.stringify({ token: bearerToken, apiBaseUrl: worker.rpcUrl }),
 78→		);
 79→
 80→		const sessionFile = join(projectDir, "e2e-test-session.jsonl");
 81→		await writeFile(
 82→			sessionFile,
 83→			[
 84→				JSON.stringify({
 85→					type: "summary",
 86→					sessionId: "e2e-test-session",
 87→				}),
 88→				JSON.stringify({
 89→					type: "message",
 90→					role: "human",
 91→					content: "test",
 92→				}),
 93→			].join("\n"),
 94→		);
 95→
 96→		const cliPath = join(import.meta.dir, "..", "bin", "cli.ts");
 97→		const proc = Bun.spawn(
 98→			["bun", cliPath, "upload", sessionFile, "--endpoint", worker.rpcUrl],
 99→			{
100→				stdout: "pipe",
101→				stderr: "pipe",
102→				env: {
103→					...process.env,
104→					RUDEL_CONFIG_DIR: credDir,
105→				},
106→			},
107→		);
108→
109→		const exitCode = await proc.exited;
110→		const stdout = await new Response(proc.stdout).text();
111→		const stderr = await new Response(proc.stderr).text();
112→
113→		expect(stdout).toContain("Upload successful!");
114→		expect(exitCode).toBe(0);
115→		if (stderr) {
116→			expect(stderr).toBe("");
117→		}
118→	});
119→
120→	test("rejects unauthenticated requests", async () => {
121→		const request: IngestRequest = {
122→			sessionId: "unauth-test",
123→			projectPath: "/test/unauth",
124→			content: "should fail",
125→		};
126→
127→		const result = await uploadSession(request, {
128→			endpoint: worker.rpcUrl,
129→			token: "invalid-token",
130→		});
131→
132→		expect(result.success).toBe(false);
133→	});
134→});
135→

